var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장, 끝도 없이 몰려오는군.","JPN":"くっそ、きりがないな。","ENG":"Dammit, there's no end to them!","TWN":"可惡，沒完沒了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"대장님! 뭔가 이상합니다! 적의 탄환에 맞은 대원들이……!","JPN":"隊長！　何かおかしいです！　敵の弾丸に撃たれた隊員たちが……！","ENG":"Commander! Something's wrong! Our soldiers hit by the enemy bullets are–!","TWN":"隊長！不對勁啊！被敵人子彈打中的隊員們……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"컥……! 아, 안 돼……!","JPN":"かはっ……！　だ、駄目だ……！","ENG":"Gah...! N-no...!","TWN":"呃……！不，不要……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"어이, 괜찮나!","JPN":"おい、大丈夫か！","ENG":"Hey! You all right?!","TWN":"喂，你沒事吧！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"으아, 으아아아아아아아악……!!","JPN":"うああ、ああああああああ……！！","ENG":"Agh...! AAAAAAARGH...!!","TWN":"呃啊，呃啊啊啊啊啊啊啊……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"이, 이런 제기랄……!!","JPN":"そ、そんな……くそ！！","ENG":"D-dammit...!!","TWN":"該，該死……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어이, 대장님! 괜찮아?","JPN":"おい、隊長！　大丈夫か？","ENG":"Oi, Commander! You good?","TWN":"喂，隊長！你沒事吧？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"가, 감사합니다! 요원님!","JPN":"あ、ありがとうございます！","ENG":"Th-thank you! Agent!","TWN":"謝，謝謝！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 미친 자식들! 이젠 하다하다 총알에 파편을 담아서 쏘고 있잖아?","JPN":"あいつら……！　弾丸に破片を入れ込んでやがる！","ENG":"Those wankers! They're firing bullets containing Fragments now?!","TWN":"這些瘋子！竟然在子彈裡裝了碎片？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어머니의 보살핌 아래에 우리는 곧 하나가 될 지니.","JPN":"母の腕の中で、我々はもうじき一つになる。","ENG":"Under Mother's care, we will soon become one.","TWN":"在母親的關懷下，我們即將合而為一。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"저기다! 죽음을 두려워하는 불신자들이 저곳에……!","JPN":"あそこだ！　死を恐れる不信者たちがあそこに……！","ENG":"There they are! The nonbelievers who fear death are over th–","TWN":"在那裡！懼怕死亡的非信徒就在那裡……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"집중하세요, 버넷 요원.","JPN":"集中してください、エージェント・バーネット。","ENG":"Focus, Agent Burnett.","TWN":"伯內特，請集中精神。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신이 전열에서 빠져버리면 즉시 대열이 흐트러집니다.","JPN":"あなたが戦列から外れると、隊列が乱れてしまいます。","ENG":"The moment you fall out of the front, the entire formation will collapse.","TWN":"你到前線的話，隊形就會立刻亂掉。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잔해에게 가장 유효한 공격을 취할 수 있는 건, 우리 중에 당신 밖에 없어요.","JPN":"私たちの中で残骸にもっとも有効な攻撃ができるのは、あなたしかいないのです。","ENG":"You are the only one who can effectively attack the Remains.","TWN":"能對殘骸發動最有效攻擊的人，我們當中就只有你一個了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるせえ！","ENG":"Shut it!","TWN":"吵死了！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 내 뒤에 있는 사람들이 저격당하는 걸 구경만 하고 있으라는 거야!?","JPN":"じゃあ俺の後ろにいるやつらが狙撃されるのを指くわえて見てろってことか！？","ENG":"Do you expect me to sit back and do nothing as they snipe all those people behind me?!","TWN":"那你是想讓我眼睜睜地看著後面的人被射中嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"난 그런 꼴은 못 봐!!","JPN":"俺にはそんなことできねえ！！","ENG":"Not on my watch!!","TWN":"我可做不到！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"전열을 유지하지 못해서 대열이 무너지면 전멸입니다!","JPN":"隊列が崩れてしまったら全滅です！","ENG":"We will be annihilated if we cannot maintain our formation!","TWN":"如果因為保持不了隊形，而導致隊形瓦解，我們就會全軍覆沒！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"지금이 기회다!","JPN":"今だ！","ENG":"Now's our chance!","TWN":"現在就是機會！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L1_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"쇠사슬을 든 녀석을 노려! 녀석만 없으면 우리에게 승기가……!","JPN":"鎖を持ってるやつを狙え！　やつさえ倒せば俺たちに勝ち目が……！","ENG":"Aim for the one with the chain! It will be our victory if he's–","TWN":"盯著拿著鐵鍊的傢伙！如果沒有他，我們就有機會贏……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"으악……!!","JPN":"くああっ！！","ENG":"Aaargh...!!","TWN":"呃啊……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"승기가 있을 것 같다고? 날 까먹고 있다니 이거 섭섭한데?","JPN":"勝ち目がある？　アタシのことを忘れてくれちゃ困るよ？","ENG":"Victory? I'm upset that you forgot about me!","TWN":"啊咧？會有機會贏？竟然忘了還有我，真是令人傷心啊？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"으악! 학회장이 부리는 미치광이다!","JPN":"うわあっ！　学会長のとこのいかれた娘だ！","ENG":"Agh! It's the lunatic the President keeps around!","TWN":"啊！是學會會長手下的瘋子！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"저 녀석을 대열에 합류하지 못하게 해! 묶어 두는 거다!","JPN":"あいつを阻止しろ！　合流できないように引き止めるんだ！","ENG":"Don't let her join the formation! Keep her busy!","TWN":"要牽制住她！別讓她加入隊伍！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아하핫, 영지 청소 할때도 느꼈지만 말이야.","JPN":"あははっ、領地を掃除する時も思ったけどね。","ENG":"Ahaha. You know, I felt it when I was cleaning up the estate, but...","TWN":"哈哈哈，我在打掃領地的時候就感覺到了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"이 녀석들은 흐물흐물해서 쏘는 맛이 별로랄까? 아무튼 재미없다구~","JPN":"こいつらはふにゃふにゃしててあまり撃ち甲斐がないっていうか、つまんないんだよね～","ENG":"these things are too squishy and no fun to shoot.","TWN":"這些傢伙軟乎乎的，射擊的手感並不怎麼樣！反正就是沒意思～"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그럼, 난 사람 머리 쏘러 갈게, 바이바이~","JPN":"じゃあアタシは人の頭を撃ちに行くから。バイバイ～","ENG":"So, I'll go pop off people's heads! Bye-bye!","TWN":"那我去找人頭來射了，拜拜~"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야! 어디가!","JPN":"おい、どこ行くんだ！","ENG":"Oi! Where do you think you're going?!","TWN":"喂！你去哪裡！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제길, 저 토끼녀는 도움이 되는 지, 안 되는 지 모르겠네!","JPN":"くそ、あのウサギ女……役に立つのか、立たないのかわかんねぇ！","ENG":"Dammit. I can't tell if that bunny girl's any help or not!","TWN":"該死，那個兔子女不知道是不是在幫忙！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그쪽입니다! 한 눈 팔지 마세요!","JPN":"そっちです！　よそ見しないでください！","ENG":"One is heading your way! Watch out!","TWN":"那邊！不要分心！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……헛?","JPN":"……はっ！","ENG":"...Huh?","TWN":"……嚇？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"하아…… 젠장, 빚은 갚았습니다. 요원님.","JPN":"はあ……くそ、これで借りは返しましたよ。","ENG":"*Sigh...* Dammit. My debt's been paid, Agent.","TWN":"哈啊……可惡，我的債還清了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 대장님……?","JPN":"なんだ、隊長……？","ENG":"Huh? Commander...?","TWN":"怎麼回事，隊長……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"괜찮아? 정신 차리라고!","JPN":"大丈夫か？　しっかりしろ！","ENG":"Oi! You okay?! Wake up!","TWN":"你沒事吧？快打起精神來！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"상처를 막아서 응급조치를 했습니다!","JPN":"傷を塞いで応急手当をしました！","ENG":"I have treated his wound with first aid!","TWN":"我堵住了傷口，做了急救措施！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그보다 전투에 집중하세요. 모두를 신경쓰면서 싸울 수는 없습니다!","JPN":"それより戦闘に集中してください。全員に気を配りながら戦うことはできません！","ENG":"Focus on the battle. There is no time to fight while caring for everyone!","TWN":"比起這個，請把精力集中在戰鬥上。我們沒法顧全每一個人！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 이상 인원이 빠지면 대열 자체가 무의미해요.","JPN":"これ以上人数が減ってしまうと、隊列が無意味になります。","ENG":"The formation will become useless if any more personnel leave their ranks.","TWN":"如果人員再減少下去，隊形就會失去意義。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 제기랄……!","JPN":"こんちくしょう……！","ENG":"Goddammit...!!","TWN":"該死的……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"쏴라! 탄환을 아까지 말고 쏟아부어!","JPN":"撃て！　弾丸を惜しむな！","ENG":"FIRE! Give 'em hell with all the bullets you got!","TWN":"射擊！不要省子彈，全部給我射擊！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"전열을 유지해! 수녀님과 요원님이 잔해를 제거할 수 있도록 길을 여는 거다!","JPN":"戦列を維持しろ！　シスターとエージェントが残骸を排除できるように、道を切り開くんだ！","ENG":"Maintain the formation! And pave the way for Sister and Agent to get rid of the Remains!","TWN":"保持戰鬥隊形！為修女和大人清除殘骸開路！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color>知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整的</color>知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得完整<b></b>……"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"빌어먹을. 이렇게 나온다 이거지?","JPN":"ちくしょう、そう来るってことか。","ENG":"Bloody hell. So this is how it's gonna be?","TWN":"該死，還來這一套？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"답답해 죽겠네. 그냥 저 흐물흐물한 녀석들을 전부 족쳐버리면 되는 거 아니야?","JPN":"うっとうしいな。あのふにゃっとした奴ら全部ぶっ倒せばいいんじゃないのか？","ENG":"This is bloody infuriating! Can't I just clean out those squishy things?","TWN":"煩死了，把那些軟趴趴的傢伙都給踹了不就可以了嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내 CRF가 먼저 바닥나든, 이 잔해들이 먼저 박살나든.","JPN":"俺のCRFが先に切れるか、この残骸たちが先に潰れるか。","ENG":"So either I run out of CRF, or I kill them all.","TWN":"不管是先用完我的CRF，還是先打爛這些殘骸。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어쨌든 둘 중 하나잖아, 안 그래?","JPN":"どっちか先だろ。なあ？","ENG":"It's one of those two outcomes, right?","TWN":"反正是二者之一，不是嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 덤비라고! 이 망할 침식체들아!","JPN":"さあ、かかってこい！　くそ侵食体ども！","ENG":"All right then! Come at me, you dirty C.O. bastards!","TWN":"來啊！你們這些侵蝕體！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color>知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整的</color>知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得完整<b></b>……"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L20_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"……<color=#ff3636>버</color><b>넷</b>?","JPN":"……<color=#ff3636>バー</color><b>ネット</b>？","ENG":"...<color=#ff3636>Bur</color><b>nett</b>?","TWN":"……<color=#ff3636>伯</color><b>內特</b>？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"방금, 뭐라고……?","JPN":"今、何て……？","ENG":"What... did you just say?","TWN":"剛才，你說什麼……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};